public class ToStringBug {
    int x, y;
    ToStringBug(int x, int y) { this.x=x; this.y=y; }
    public String toString() {
        return "(" + x + "," + y + ")";
    }
    public static void main(String[] args) {
        ToStringBug p = new ToStringBug(3, 4);
        System.out.println(p.toString());
        System.out.println("Point: " + p);
        // No bug above — but see below:
        ToStringBug q = null;
        System.out.println("q=" + q.toString());  // bug: NPE
    }
}
